#include "ucminf_core.hpp" #include <iostream>  int main() {     // Rosenbrock's Banana Function     auto banana = [](const std::vector<double>& x,                      std::vector<double>& g,                      double& f) {         double a = 1.0 - x[0];         double b = x[1] - x[0] * x[0];         f    =  a * a + 100.0 * b * b;         g[0] = -2.0 * a - 400.0 * x[0] * b;         g[1] =  200.0 * b;     };      ucminfcpp::Result res = ucminfcpp::minimize({-1.2, 1.0}, banana);      std::cout << "par  = (" << res.par[0] << ", " << res.par[1] << ")
";     std::cout << "f    = " << res.value << "
";     std::cout << "conv = " << res.convergence << "
";     return 0; }
